const f=a=>{if(!a)return"";const c={january:"جنوري",february:"فيبروري",march:"مارچ",april:"اپريل",may:"مئي",june:"جون",july:"جولائي",august:"آگسٽ",september:"سيپٽمبر",october:"آڪٽوبر",november:"نومبر",december:"ڊسمبر",jan:"جنوري",feb:"فيبروري",mar:"مارچ",apr:"اپريل",jun:"جون",jul:"جولائي",aug:"آگسٽ",sep:"سيپٽمبر",oct:"آڪٽوبر",nov:"نومبر",dec:"ڊسمبر"},n=a.match(/([a-zA-Z]+|\d+)/g);if(n&&n.length>=3){const t=n.find(e=>e.length===4&&!isNaN(e)),r=n.find(e=>isNaN(e)),o=n.find(e=>e!==t&&!isNaN(e));if(o&&r&&t){const e=r.toLowerCase(),i=c[e]||r;return`${o} ${i}، ${t}`}}let s=a;for(const[t,r]of Object.entries(c)){const o=new RegExp(`\\b${t}\\b`,"gi");s=s.replace(o,r)}return s.replace(",","،")};export{f};
